-- Ken's Hardened V2 Fix

local b64_0xIlI1lI = {}
local char_0xI1IllI='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xII11II=1,#char_0xI1IllI do b64_0xIlI1lI[char_0xI1IllI:sub(i_0xII11II,i_0xII11II)] = i_0xII11II - 1 end

function b64_0xIlI1lI.dec_0x11lIll(d_0xIIIll1)
    d_0xIIIll1 = string.gsub(d_0xIIIll1, '[^'..char_0xI1IllI..'=]', '')
    local r_0xIl11Il = {}
    for i_0xII11II=1, #d_0xIIIll1, 4 do
        local c_0xlII1Il = b64_0xIlI1lI[d_0xIIIll1:sub(i_0xII11II,i_0xII11II)] or 0
        local c_0xIIlII1 = b64_0xIlI1lI[d_0xIIIll1:sub(i_0xII11II+1,i_0xII11II+1)] or 0
        local c_0xlllIIl, c_0xI1IlIl = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xIIIll1:sub(i_0xII11II+2,i_0xII11II+2)
        if ch3 == "=" then has3 = false else c_0xlllIIl = b64_0xIlI1lI[ch3] or 0 end
        local ch4 = d_0xIIIll1:sub(i_0xII11II+3,i_0xII11II+3)
        if ch4 == "=" then has4 = false else c_0xI1IlIl = b64_0xIlI1lI[ch4] or 0 end
        local b_0xlIll1I = c_0xlII1Il * (2^18) + c_0xIIlII1 * (2^12) + c_0xlllIIl * (2^6) + c_0xI1IlIl
        local b_0x1lI1lI = math.floor(b_0xlIll1I / (2^16)) % (2^8)
        local b_0xlIlll1 = math.floor(b_0xlIll1I / (2^8)) % (2^8)
        local b_0xllIIlI = b_0xlIll1I % (2^8)
        table.insert(r_0xIl11Il, string.char(b_0x1lI1lI))
        if has3 then table.insert(r_0xIl11Il, string.char(b_0xlIlll1)) end
        if has4 then table.insert(r_0xIl11Il, string.char(b_0xllIIlI)) end
    end
    return table.concat(r_0xIl11Il)
end


local function bxor_0xl1111l(a_0xI111l1,b_0xlllI1l)
    if bit32 then return bit32.bxor(a_0xI111l1,b_0xlllI1l) end
    local r_0xl1l1ll = 0
    for i_0xIll1Il = 0, 7 do
        local x_0xlllIII = a_0xI111l1 % 2
        local y_0x1111Il = b_0xlllI1l % 2
        if x_0xlllIII ~= y_0x1111Il then r_0xl1l1ll = r_0xl1l1ll + (2^i_0xIll1Il) end
        a_0xI111l1 = math.floor(a_0xI111l1 / 2)
        b_0xlllI1l = math.floor(b_0xlllI1l / 2)
    end
    return r_0xl1l1ll
end


local function bxor_str_0x1Illll(s_0xIIII1I, k_0xIll1lI)
    local r_0xIIIIII = {}
    for i_0x1Illl1=1, #s_0xIIII1I do
        local b_0xIll1Il = string.byte(s_0xIIII1I, i_0x1Illl1)
        local kb_0xll1l1l = string.byte(k_0xIll1lI, (i_0x1Illl1-1) % #k_0xIll1lI + 1)
        r_0xIIIIII[i_0x1Illl1] = string.char(bxor_0xl1111l(b_0xIll1Il, kb_0xll1l1l))
    end
    return table.concat(r_0xIIIIII)
end


local function getkeys_0xII1IIl()
    local seed = b64_0xIlI1lI.dec_0x11lIll("QlJRZzRpRmY=")
    local k1_enc = b64_0xIlI1lI.dec_0x11lIll("Mz0IKGwzKSk=")
    local k2_enc = b64_0xIlI1lI.dec_0x11lIll("EyI9HWAbLxQ=")
    return bxor_str_0x1Illll(k1_enc, seed), bxor_str_0x1Illll(k2_enc, seed)
end


local function cff_0xlIlII1(a_0xll1III)
    local st_0x11I111 = 0
    local res_0xllllI1 = a_0xll1III
    while true do
        if st_0x11I111 == 0 then
            res_0xllllI1 = res_0xllllI1 + 1
            st_0x11I111 = 1
        elseif st_0x11I111 == 1 then
            res_0xllllI1 = res_0xllllI1 * 2
            st_0x11I111 = 2
        elseif st_0x11I111 == 2 then
            res_0xllllI1 = res_0xllllI1 - 3
            st_0x11I111 = 3
        else
            break
        end
    end
    return res_0xllllI1
end


local function chain_0xlIllll(x) return x*2 end
local function chain_0xI1IllI(x) return chain_0xlIllll(x)+1 end


local d_0xIIl11l = {
  {op=255, val="", is_enc=true},
}
local pc_0xlIlllI = 1
local stk_0xIllII1 = {}
stk_0xIllII1._jmp = nil


local disp_0xlII1Il = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xII1IIl()

local state_0xIIIIll = 0
while true do
    if state_0xIIIIll == 0 then  -- FETCH
        if pc_0xlIlllI > #d_0xIIl11l then break end
        local inst = d_0xIIl11l[pc_0xlIlllI]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xIlI1lI.dec_0x11lIll(val)
            d = bxor_str_0x1Illll(d, k2)
            val = bxor_str_0x1Illll(d, k1)
        end
        stk_0xIllII1._jmp = nil
        pc_0xlIlllI = pc_0xlIlllI + 1
        cur_op_0xIlII11 = opcode
        cur_val_0xlIlIl1 = val
        state_0xIIIIll = 1

    elseif state_0xIIIIll == 1 then  -- EXECUTE
        local handler = disp_0xlII1Il[cur_op_0xIlII11]
        if handler then
            handler(stk_0xIllII1, cur_val_0xlIlIl1)
        end
        if stk_0xIllII1._jmp then
            pc_0xlIlllI = pc_0xlIlllI + stk_0xIllII1._jmp
        end
        state_0xIIIIll = 0
    else
        break
    end
end
